import { pulseBoardPlugin } from "./src/channel.js";

export default defineSetupPluginEntry(pulseBoardPlugin);
```

**api.ts** - Public API barrel (exports helpers):
```typescript
export * from "./src/accounts.js";
export * from "./src/setup-surface.js";
// ... other public utilities
```

**runtime-api.ts** - Runtime barrel (re-exports SDK):
```typescript
// Private runtime barrel for the bundled plugin
export * from "openclaw/plugin-sdk/pulseBoard";
// or for new channels without SDK support:
export type { ChannelPlugin, OpenClawConfig, PluginRuntime } from "openclaw/plugin-sdk/core";
```

### 5. RUNTIME MANAGEMENT (runtime.ts)

All plugins follow this pattern:
```typescript
import { createPluginRuntimeStore } from "openclaw/plugin-sdk/runtime-store";
import type { PluginRuntime } from "./runtime-api.js";

const { setRuntime: setPulseBoardRuntime, getRuntime: getPulseBoardRuntime } =
  createPluginRuntimeStore<PluginRuntime>("PulseBoard runtime not initialized");
export { getPulseBoardRuntime, setPulseBoardRuntime };
export function clearPulseBoardRuntime() {
  setPulseBoardRuntime(undefined as unknown as PluginRuntime);
}
```

### 6. CHANNEL PLUGIN DEFINITION (src/channel.ts)

This is the **CORE FILE** - defines the entire channel behavior. Key structure:

```typescript
export const pulseBoardPlugin: ChannelPlugin<ResolvedAccount, ProbeType> = 
  createChatChannelPlugin({
    base: {
      id: "pulseBoard",
      meta: { /* channel metadata */ },
      capabilities: {
        chatTypes: ["direct", "group"],  // or just ["direct"]
        media: true,                      // or false
      },
      reload: { configPrefixes: ["channels.pulseBoard"] },
      configSchema: buildChannelConfigSchema(ConfigSchema),
      setup: setupAdapter,
      setupWizard: setupWizard,
      config: { /* config adapter */ },
      messaging: { /* message routing */ },
      resolver: { /* target resolution */ },
      directory: { /* peer/group listing */ },
      groups: { /* group-specific policies */ },
      status: { /* connection status */ },
      gateway: { /* start/stop */ },
    },
  });
```

Key plugin capabilities from the examples:
- **chatTypes**: `["direct"]` (DM-only like Nostr) or `["direct", "group"]` (IRC, Telegram)
- **media**: true/false for attachment support
- **blockStreaming** (IRC): prevent streaming responses
- **reactions** (Telegram): emoji reaction support
- **markdown** (Telegram): markdown formatting support

### 7. CONFIGURATION SCHEMA (src/config-schema.ts)

Use Zod for validation:

```typescript
import { buildChannelConfigSchema, DmPolicySchema, MarkdownConfigSchema } from "openclaw/plugin-sdk/channel-config-schema";
import { z } from "openclaw/plugin-sdk/zod";

const PulseBoardAccountSchema = z.object({
  name: z.string().optional(),
  enabled: z.boolean().optional(),
  apiKey: z.string().optional(),  // Your auth credential
  apiUrl: z.string().url().optional(),
  dmPolicy: DmPolicySchema.optional().default("pairing"),
  allowFrom: z.array(z.union([z.string(), z.number()])).optional(),
  markdown: MarkdownConfigSchema,
}).strict();

export const PulseBoardConfigSchema = buildChannelConfigSchema(
  z.object({
    defaultAccount: z.string().optional(),
    accounts: z.record(z.string(), PulseBoardAccountSchema).optional(),
  }).strict(),
);
```

### 8. ACCOUNT RESOLUTION (src/accounts.ts & src/types.ts)

Pattern for resolving configuration into typed accounts:

```typescript
import { createAccountListHelpers } from "openclaw/plugin-sdk/account-helpers";
import { DEFAULT_ACCOUNT_ID, normalizeAccountId } from "openclaw/plugin-sdk/account-id";
import { resolveMergedAccountConfig } from "openclaw/plugin-sdk/account-resolution";

export type ResolvedPulseBoardAccount = {
  accountId: string;
  enabled: boolean;
  configured: boolean;
  apiKey: string;
  apiUrl: string;
  config: PulseBoardAccountConfig;
};

export function resolvePulseBoardAccount(opts: {
  cfg: OpenClawConfig;
  accountId?: string | null;
}): ResolvedPulseBoardAccount {
  const accountId = normalizeAccountId(opts.accountId ?? "default");
  const cfg = (opts.cfg.channels as Record<string, unknown> | undefined)?.pulseBoard as 
    | PulseBoardAccountConfig | undefined;

  const merged = resolveMergedAccountConfig<PulseBoardAccountConfig>({
    channelConfig: cfg,
    accounts: cfg?.accounts,
    accountId,
    normalizeAccountId,
  });

  return {
    accountId,
    enabled: merged.enabled !== false,
    configured: Boolean(merged.apiKey),
    apiKey: merged.apiKey ?? "",
    apiUrl: merged.apiUrl ?? DEFAULT_URL,
    config: merged,
  };
}

const { listAccountIds, resolveDefaultAccountId } = createAccountListHelpers("pulseBoard", {
  normalizeAccountId,
});
export { listAccountIds as listPulseBoardAccountIds };
```

### 9. MESSAGE SENDING (src/send.ts)

Outbound message implementation:

```typescript
export async function sendMessagePulseBoard(
  target: string,
  text: string,
  options?: SendOptions,
): Promise<SendResult> {
  const runtime = getPulseBoardRuntime();
  const cfg = runtime.config.loadConfig();
  const account = resolvePulseBoardAccount({ cfg, accountId: options?.accountId });

  // Validate configured
  if (!account.configured) {
    throw new Error("PulseBoard not configured");
  }

  // Build API payload
  const payload = {
    recipient: target,
    message: text,
  };

  // Send via API
  const response = await fetch(`${account.apiUrl}/messages/send`, {
    method: "POST",
    headers: {
      "Authorization": `Bearer ${account.apiKey}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify(payload),
  });

  if (!response.ok) {
    throw new Error(`Failed to send: ${response.statusText}`);
  }

  return {
    channelId: "pulseBoard",
    to: target,
    messageId: (await response.json()).messageId,
  };
}
```

### 10. INBOUND MESSAGE HANDLING (src/inbound.ts)

Handle incoming messages from the provider:

```typescript
export async function dispatchInboundPulseBoard(params: {
  cfg: OpenClawConfig;
  message: InboundMessage;
  runtime: PluginRuntime;
}): Promise<void> {
  const { cfg, message, runtime } = params;
  const account = resolvePulseBoardAccount({ cfg, accountId: message.accountId });

  // Dispatch to core system
  await dispatchInboundDirectDmWithRuntime({
    channel: "pulseBoard",
    cfg,
    accountId: message.accountId,
    senderId: message.senderId,
    rawBody: message.text,
    kind: "message",
    conversationId: message.senderId,
    messageId: message.messageId,
    receivedAt: new Date(),
    runtime,
  });
}
```

### 11. PROVIDER MONITORING (src/monitor.ts)

Polling or webhook-based message polling:

```typescript
export async function monitorPulseBoardProvider(params: {
  cfg: OpenClawConfig;
  accountId: string;
  runtime: PluginRuntime;
  onEvent: (event: InboundMessage) => Promise<void>;
  signal?: AbortSignal;
}): Promise<void> {
  const { cfg, accountId, onEvent, signal } = params;
  const account = resolvePulseBoardAccount({ cfg, accountId });

  if (!account.configured) {
    throw new Error("PulseBoard not configured");
  }

  // Long-polling example
  while (!signal?.aborted) {
    try {
      const response = await fetch(`${account.apiUrl}/messages/poll`, {
        headers: { "Authorization": `Bearer ${account.apiKey}` },
        signal,
      });
      const messages = await response.json();

      for (const msg of messages) {
        await onEvent(msg);
      }
    } catch (err) {
      if (err instanceof DOMException && err.name === "AbortError") break;
      // Log error and retry
      await new Promise(r => setTimeout(r, 5000));
    }
  }
}
```

### 12. CONNECTION PROBING (src/probe.ts)

Test connectivity without full startup:

```typescript
export interface PulseBoardProbe {
  ok: boolean;
  at?: Date;
  latency?: number;
  error?: string;
}

export async function probePulseBoard(
  cfg: OpenClawConfig,
  opts: { accountId?: string; timeoutMs?: number },
): Promise<PulseBoardProbe> {
  const account = resolvePulseBoardAccount({ cfg, accountId: opts.accountId });

  if (!account.configured) {
    return { ok: false, error: "Not configured" };
  }

  try {
    const start = Date.now();
    const response = await fetch(`${account.apiUrl}/health`, {
      headers: { "Authorization": `Bearer ${account.apiKey}` },
      signal: AbortSignal.timeout(opts.timeoutMs ?? 5000),
    });
    const latency = Date.now() - start;

    return {
      ok: response.ok,
      at: new Date(),
      latency,
      error: response.ok ? undefined : response.statusText,
    };
  } catch (err) {
    return {
      ok: false,
      at: new Date(),
      error: String(err),
    };
  }
}
```

### 13. SETUP WIZARD (src/setup-surface.ts)

Interactive configuration prompts:

```typescript
