import type { DmPolicy, GroupPolicy } from "./runtime-api.js";

/**
 * Per-board configuration (mirrors IRC channel config pattern).
 */
export type PulseBoardGroupConfig = {
  /** Override the require-mention setting for this specific board. */
  requireMention?: boolean;
  /** Restrict which sender handles may trigger responses in this board. */
  allowFrom?: Array<string | number>;
  /** Whether this board entry is enabled for routing. */
  enabled?: boolean;
  /** Optional per-board system prompt override. */
  systemPrompt?: string;
};

/**
 * Per-account configuration for the PulseBoard channel.
 * The top-level config section (channels.pulseboard.*) also matches this shape.
 */
export type PulseBoardAccountConfig = {
  /** Optional display name for this account. */
  name?: string;
  /** Whether this account is enabled. Defaults to true. */
  enabled?: boolean;
  /** PulseBoard API key (Bearer token). */
  apiKey?: string;
  /** PulseBoard API base URL. Defaults to DEFAULT_PULSEBOARD_API_URL. */
  apiUrl?: string;
  /** The bot's own handle on PulseBoard (e.g. "mybot"). Required for board messages. */
  botHandle?: string;
  /** DM access policy: pairing | allowlist | open | disabled. */
  dmPolicy?: DmPolicy;
  /** Allowed sender handles for DMs. */
  allowFrom?: Array<string | number>;
  /** Group (board) access policy: allowlist | open | disabled. */
  groupPolicy?: GroupPolicy;
  /** Allowed board names for group routing. */
  groupAllowFrom?: Array<string | number>;
  /** Per-board configuration keyed by board name (e.g. "#general"). */
  groups?: Record<string, PulseBoardGroupConfig>;
  /** Boards to auto-join on startup (e.g. ["#general", "#ops"]). */
  boards?: string[];
  /** Markdown table rendering override. */
  markdown?: { tableMode?: "plain" | "html" | "image" };
  /** Long-poll interval in milliseconds. Defaults to 2000. */
  pollIntervalMs?: number;
};

/**
 * Top-level channels.pulseboard config shape, including multi-account support.
 */
export type PulseBoardConfig = PulseBoardAccountConfig & {
  accounts?: Record<string, PulseBoardAccountConfig>;
  defaultAccount?: string;
};

/**
 * The full OpenClaw config type narrowed to include pulseboard channel config.
 */
export type CoreConfig = {
  channels?: {
    pulseboard?: PulseBoardConfig;
    [key: string]: unknown;
  };
  [key: string]: unknown;
};

/**
 * A normalized inbound message received from the PulseBoard API.
 */
export type PulseBoardInboundMessage = {
  /** Unique message ID from the PulseBoard API. */
  messageId: string;
  /** Sender handle (e.g. "alice"). */
  senderHandle: string;
  /**
   * Conversation target: board name for board messages (e.g. "#general"),
   * or bot handle for DMs.
   */
  target: string;
  /** Raw message text. */
  text: string;
  /** Unix timestamp in milliseconds. */
  timestamp: number;
  /** Whether this message arrived in a board (group) rather than a DM. */
  isBoard: boolean;
  /** Board name when isBoard is true (e.g. "#general"). */
  boardName?: string;
};

/**
 * Probe result for a PulseBoard account connection check.
 */
export type PulseBoardProbe = {
  ok: boolean;
  at?: Date;
  latencyMs?: number;
  error?: string;
};

