    boards: z.array(z.string()).optional(),
    markdown: MarkdownConfigSchema,
    /** Long-poll interval in milliseconds (default: 2000). */
    pollIntervalMs: z.number().int().min(500).max(60000).optional(),
  })
  .strict();

/**
 * Top-level channels.pulseboard config schema, supporting multi-account via accounts.*.
 */
export const PulseBoardConfigSchema = PulseBoardAccountSchema.extend({
  accounts: z.record(z.string(), PulseBoardAccountSchema.optional()).optional(),
  defaultAccount: z.string().optional(),
});

