import { createAccountListHelpers } from "openclaw/plugin-sdk/account-helpers";
import { DEFAULT_ACCOUNT_ID, normalizeAccountId } from "openclaw/plugin-sdk/account-id";
import { resolveMergedAccountConfig } from "openclaw/plugin-sdk/account-resolution";
import { normalizeResolvedSecretInputString } from "openclaw/plugin-sdk/secret-input";
import type { CoreConfig, PulseBoardAccountConfig, PulseBoardConfig } from "./types.js";

export const DEFAULT_PULSEBOARD_API_URL = "https://api.pulseboard.io";
export const DEFAULT_POLL_INTERVAL_MS = 2000;

export type ResolvedPulseBoardAccount = {
  accountId: string;
  name?: string;
  enabled: boolean;
  /** True when both apiKey and botHandle are present. */
  configured: boolean;
  apiKey: string;
  apiUrl: string;
  botHandle: string;
  config: PulseBoardAccountConfig;
};

const {
  listAccountIds: listPulseBoardAccountIds,
  resolveDefaultAccountId: resolveDefaultPulseBoardAccountId,
} = createAccountListHelpers("pulseboard", { normalizeAccountId });

export { listPulseBoardAccountIds, resolveDefaultPulseBoardAccountId };

export function resolvePulseBoardAccount(params: {
  cfg: CoreConfig;
  accountId?: string | null;
}): ResolvedPulseBoardAccount {
  const accountId = normalizeAccountId(
    params.accountId ?? resolveDefaultPulseBoardAccountId(params.cfg),
  );
  const isDefault = accountId === DEFAULT_ACCOUNT_ID;

  const channelCfg = params.cfg.channels?.pulseboard as PulseBoardConfig | undefined;
  const merged = resolveMergedAccountConfig<PulseBoardAccountConfig>({
    channelConfig: channelCfg,
    accounts: channelCfg?.accounts as
      | Record<string, Partial<PulseBoardAccountConfig>>
      | undefined,
    accountId,
    omitKeys: ["defaultAccount"],
    normalizeAccountId,
  });

  const baseEnabled = channelCfg?.enabled !== false;
  const accountEnabled = merged.enabled !== false;
  const enabled = baseEnabled && accountEnabled;

  // Resolve API key: config value or env var (default account only).
  const configApiKey = normalizeResolvedSecretInputString({
    value: merged.apiKey,
    path: `channels.pulseboard.accounts.${accountId}.apiKey`,
  });
  const apiKey = configApiKey || (isDefault ? (process.env.PULSEBOARD_API_KEY?.trim() ?? "") : "");

  // Resolve bot handle: config value or env var (default account only).
  const botHandle =
    merged.botHandle?.trim() ||
    (isDefault ? (process.env.PULSEBOARD_BOT_HANDLE?.trim() ?? "") : "");

  const apiUrl =
    merged.apiUrl?.trim() ||
    (isDefault ? (process.env.PULSEBOARD_API_URL?.trim() ?? "") : "") ||
    DEFAULT_PULSEBOARD_API_URL;

  return {
    accountId,
    name: merged.name?.trim() || undefined,
    enabled,
    configured: Boolean(apiKey && botHandle),
    apiKey,
    apiUrl,
    botHandle,
    config: merged,
  };
}

export function listEnabledPulseBoardAccounts(cfg: CoreConfig): ResolvedPulseBoardAccount[] {
  return listPulseBoardAccountIds(cfg)
    .map((accountId) => resolvePulseBoardAccount({ cfg, accountId }))
    .filter((account) => account.enabled);
}

