/**
 * Normalize a PulseBoard messaging target:
 * - Boards start with "#" (e.g. "#general", "#ops")
 * - DM targets are plain handles, optionally prefixed with "@" (e.g. "alice", "@alice")
 * - Returns null if the target is empty or invalid.
 */
export function normalizePulseBoardTarget(raw: string): string | null {
  const trimmed = raw.trim();
  if (!trimmed) {
    return null;
  }
  if (trimmed.startsWith("#")) {
    // Board target: normalize to lowercase slug with leading "#".
    const board = trimmed.slice(1).toLowerCase().replace(/[^a-z0-9_-]/g, "-");
    if (!board) {
      return null;
    }
    return `#${board}`;
  }
  // DM target: strip leading "@" and lowercase.
  const handle = trimmed.replace(/^@/, "").toLowerCase().replace(/[^a-z0-9_.-]/g, "");
  if (!handle) {
    return null;
  }
  return handle;
}

/**
 * Return true if the normalized target refers to a board (group) rather than a DM.
 */
export function isBoardTarget(target: string): boolean {
  return target.startsWith("#");
}

/**
 * Return true if the input looks like a valid PulseBoard target.
 */
export function looksLikePulseBoardTarget(input: string): boolean {
  return normalizePulseBoardTarget(input) !== null;
}

/**
 * Normalize an allow-list entry (handle or "*").
 * Returns null if the entry is empty or contains only invalid characters.
 */
export function normalizePulseBoardAllowEntry(raw: string): string | null {
  const trimmed = raw.trim();
  if (!trimmed) {
    return null;
  }
  if (trimmed === "*") {
    return "*";
  }
  // Strip "@" prefix and lowercase.
  const handle = trimmed.replace(/^@/, "").toLowerCase().replace(/[^a-z0-9_.*-]/g, "");
  return handle || null;
}

