import { resolvePulseBoardAccount } from "./accounts.js";
import type { CoreConfig, PulseBoardProbe } from "./types.js";

/**
 * Probe the PulseBoard API to verify connectivity and credentials.
 * Calls GET /v1/ping with the configured API key and measures round-trip latency.
 */
export async function probePulseBoard(
  cfg: CoreConfig,
  opts: { accountId?: string | null; timeoutMs?: number } = {},
): Promise<PulseBoardProbe> {
  const account = resolvePulseBoardAccount({ cfg, accountId: opts.accountId });

  if (!account.configured) {
    return { ok: false, error: "PulseBoard not configured (missing apiKey or botHandle)" };
  }

  const timeoutMs = opts.timeoutMs ?? 8000;
  const url = `${account.apiUrl}/v1/ping`;

  try {
    const start = Date.now();
    const response = await fetch(url, {
      method: "GET",
      headers: {
        Authorization: `Bearer ${account.apiKey}`,
        "X-PulseBoard-Handle": account.botHandle,
        "Content-Type": "application/json",
      },
      signal: AbortSignal.timeout(timeoutMs),
    });
    const latencyMs = Date.now() - start;

    if (!response.ok) {
      return {
        ok: false,
        at: new Date(),
        latencyMs,
        error: `HTTP ${response.status} ${response.statusText}`,
      };
    }

    return { ok: true, at: new Date(), latencyMs };
  } catch (err) {
    return {
      ok: false,
      at: new Date(),
      error: err instanceof Error ? err.message : String(err),
    };
  }
}

