import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import { resolveMarkdownTableMode } from "openclaw/plugin-sdk/config-runtime";
import { convertMarkdownTables } from "openclaw/plugin-sdk/text-runtime";
import { resolvePulseBoardAccount } from "./accounts.js";
import { normalizePulseBoardTarget } from "./normalize.js";
import { getPulseBoardRuntime } from "./runtime.js";
import type { CoreConfig } from "./types.js";

export type SendPulseBoardOptions = {
  cfg?: CoreConfig;
  accountId?: string;
};

export type SendPulseBoardResult = {
  messageId: string;
  target: string;
};

/**
 * Send a message via the PulseBoard REST API.
 * Works for both DMs (plain handle, e.g. "alice") and boards (e.g. "#general").
 */
export async function sendMessagePulseBoard(
  to: string,
  text: string,
  opts: SendPulseBoardOptions = {},
): Promise<SendPulseBoardResult> {
  const runtime = getPulseBoardRuntime();
  const cfg = (opts.cfg ?? runtime.config.loadConfig()) as CoreConfig;
  const account = resolvePulseBoardAccount({ cfg, accountId: opts.accountId });

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need apiKey and botHandle).`,
    );
  }

  const normalizedTo = normalizePulseBoardTarget(to);
  if (!normalizedTo) {
    throw new Error(`Invalid PulseBoard target: ${to}`);
  }

  // Apply markdown table conversion if configured.
  const tableMode = resolveMarkdownTableMode({
    cfg: cfg as Parameters<typeof resolveMarkdownTableMode>[0]["cfg"],
    channel: "pulseboard",
    accountId: account.accountId,
  });
  const body = convertMarkdownTables(text ?? "", tableMode);

  const response = await fetch(`${account.apiUrl}/v1/messages`, {
    method: "POST",
    headers: {
      Authorization: `Bearer ${account.apiKey}`,
      "X-PulseBoard-Handle": account.botHandle,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({ to: normalizedTo, text: body }),
  });

  if (!response.ok) {
    throw new Error(
      `PulseBoard send failed for account "${account.accountId}": HTTP ${response.status} ${response.statusText}`,
    );
  }

  const json = (await response.json()) as { id?: string };
  const messageId = json.id ?? `pb-${Date.now()}`;

  // Record outbound activity so status tracking stays current.
  try {
    runtime.channel.activity.record({
      channel: "pulseboard",
      accountId: account.accountId,
      direction: "outbound",
    });
  } catch {
    // Activity recording is best-effort; do not propagate errors.
  }

  return attachChannelToResult("pulseboard", {
    to: normalizedTo,
    messageId,
  }) as SendPulseBoardResult;
}

