import { resolvePulseBoardAccount, DEFAULT_POLL_INTERVAL_MS } from "./accounts.js";
import { isBoardTarget, normalizePulseBoardAllowEntry } from "./normalize.js";
import {
  createChannelPairingController,
  createPreCryptoDirectDmAuthorizer,
  dispatchInboundDirectDmWithRuntime,
  logInboundDrop,
  resolveAllowlistProviderRuntimeGroupPolicy,
  resolveDefaultGroupPolicy,
  resolveInboundDirectDmAccessWithRuntime,
} from "./runtime-api.js";
import { getPulseBoardRuntime } from "./runtime.js";
import { sendMessagePulseBoard } from "./send.js";
import type { CoreConfig, PulseBoardInboundMessage } from "./types.js";

const CHANNEL_ID = "pulseboard" as const;

function isPulseBoardSenderAllowed(senderHandle: string, allowFrom: string[]): boolean {
  const normalized = senderHandle.toLowerCase().replace(/^@/, "");
  for (const entry of allowFrom) {
    const e = String(entry).trim().replace(/^@/, "").toLowerCase();
    if (e === "*" || e === normalized) {
      return true;
    }
  }
  return false;
}

/**
 * Poll the PulseBoard API for incoming messages and dispatch them through the
 * OpenClaw reply pipeline.
 *
 * This function runs until the provided abortSignal fires, sleeping between
 * each poll cycle according to the configured pollIntervalMs.
 */
export async function monitorPulseBoardProvider(opts: {
  accountId?: string;
  cfg?: CoreConfig;
  abortSignal?: AbortSignal;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
}): Promise<{ stop: () => void }> {
  const runtime = getPulseBoardRuntime();
  const cfg = (opts.cfg ?? runtime.config.loadConfig()) as CoreConfig;
  const account = resolvePulseBoardAccount({ cfg, accountId: opts.accountId });

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need apiKey and botHandle).`,
    );
  }

  const pollIntervalMs = account.config.pollIntervalMs ?? DEFAULT_POLL_INTERVAL_MS;
  const log = runtime.logging.getChildLogger({ channel: CHANNEL_ID, accountId: account.accountId });

  const pairing = createChannelPairingController({
    core: runtime,
    channel: CHANNEL_ID,
    accountId: account.accountId,
  });

  // Pre-crypto DM authorizer: runs before decoding message text for early reject.
  const authorizeDmSender = createPreCryptoDirectDmAuthorizer({
    resolveAccess: async (senderHandle) => {
      const freshCfg = runtime.config.loadConfig() as CoreConfig;
      const freshAccount = resolvePulseBoardAccount({
        cfg: freshCfg,
        accountId: account.accountId,
      });
      return resolveInboundDirectDmAccessWithRuntime({
        cfg: freshCfg,
        channel: CHANNEL_ID,
        accountId: account.accountId,
        dmPolicy: freshAccount.config.dmPolicy ?? "pairing",
        allowFrom: freshAccount.config.allowFrom,
        senderId: senderHandle,
        rawBody: "",
        isSenderAllowed: isPulseBoardSenderAllowed,
        runtime: {
          shouldComputeCommandAuthorized:
            runtime.channel.commands.shouldComputeCommandAuthorized,
          resolveCommandAuthorizedFromAuthorizers:
            runtime.channel.commands.resolveCommandAuthorizedFromAuthorizers,
        },
      });
    },
    issuePairingChallenge: async ({ senderId, reply }) => {
      await pairing.issueChallenge({
        senderId,
        senderIdLine: `PulseBoard handle: ${senderId}`,
        sendPairingReply: reply,
        onCreated: () => {
          log.debug?.(`[${account.accountId}] pairing challenge issued for ${senderId}`);
        },
        onReplyError: (err) => {
          log.warn?.(
            `[${account.accountId}] pairing reply failed for ${senderId}: ${String(err)}`,
          );
        },
      });
    },
    onBlocked: ({ senderId, reason }) => {
      log.debug?.(`[${account.accountId}] blocked DM sender ${senderId} (${reason})`);
    },
  });

  // Track poll cursor so we only fetch new messages each cycle.
  let cursor: string | null = null;
  let stopped = false;

  const sleep = (ms: number) =>
    new Promise<void>((resolve) => {
      const timer = setTimeout(resolve, ms);
      opts.abortSignal?.addEventListener("abort", () => {
        clearTimeout(timer);
        resolve();
      });
    });

  const poll = async (): Promise<void> => {
    while (!stopped && !(opts.abortSignal?.aborted)) {
      try {
        const params = new URLSearchParams({ limit: "50" });
        if (cursor) {
          params.set("after", cursor);
        }

        const response = await fetch(
          `${account.apiUrl}/v1/messages/incoming?${params.toString()}`,
          {
            headers: {
              Authorization: `Bearer ${account.apiKey}`,
              "X-PulseBoard-Handle": account.botHandle,
            },
            signal: opts.abortSignal,
          },
        );

        if (!response.ok) {
          log.warn?.(
            `[${account.accountId}] poll HTTP ${response.status}; will retry in ${pollIntervalMs}ms`,
          );
        } else {
          const data = (await response.json()) as {
            messages?: Array<{
              id: string;
              from: string;
              to: string;
              text: string;
              ts: number;
              isBoard?: boolean;
              boardName?: string;
            }>;
            cursor?: string;
          };

          if (data.cursor) {
            cursor = data.cursor;
          }

          for (const raw of data.messages ?? []) {
            const msg: PulseBoardInboundMessage = {
              messageId: raw.id,
              senderHandle: raw.from,
              target: raw.to,
              text: raw.text ?? "",
              timestamp: raw.ts,
              isBoard: Boolean(raw.isBoard),
              boardName: raw.boardName,
            };
            await handleInboundMessage(msg, account.accountId, cfg).catch((err) => {
              log.error?.(
                `[${account.accountId}] inbound dispatch error for msg ${msg.messageId}: ${String(err)}`,
              );
            });
          }
        }
      } catch (err) {
        if (opts.abortSignal?.aborted) {
          break;
        }
        log.error?.(`[${account.accountId}] poll error: ${String(err)}`);
      }

      if (!stopped && !(opts.abortSignal?.aborted)) {
        await sleep(pollIntervalMs);
      }
    }
  };

  // Start polling in the background; return a stop handle.
  const pollPromise = poll();

  return {
    stop: () => {
      stopped = true;
      pollPromise.catch(() => {});
    },
  };
}

async function handleInboundMessage(
  msg: PulseBoardInboundMessage,
  accountId: string,
  cfg: CoreConfig,
): Promise<void> {
  const runtime = getPulseBoardRuntime();
  const rawBody = msg.text.trim();
  if (!rawBody) {
    return;
  }

  const account = resolvePulseBoardAccount({ cfg, accountId });

  if (msg.isBoard) {
    await handleBoardMessage(msg, account.accountId, cfg);
  } else {
    await handleDirectMessage(msg, account.accountId, cfg);
  }
}

/**
 * Handle an incoming direct message from the PulseBoard API.
 */
async function handleDirectMessage(
  msg: PulseBoardInboundMessage,
  accountId: string,
  cfg: CoreConfig,
): Promise<void> {
  const runtime = getPulseBoardRuntime();
  const rawBody = msg.text.trim();

  // Run pre-auth check before full dispatch.
  const preAuthDecision = await authorizeDmSenderForAccount(msg.senderHandle, accountId, cfg);
  if (preAuthDecision === "block") {
    logInboundDrop({
      channel: CHANNEL_ID,
      accountId,
      reason: "dm-blocked",
      senderId: msg.senderHandle,
    });
    return;
  }
  if (preAuthDecision === "pairing") {
    // Pairing challenge was already issued by the pre-auth hook; skip dispatch.
    return;
  }

  // Full access resolution with command auth.
  const account = resolvePulseBoardAccount({ cfg, accountId });
  const access = await resolveInboundDirectDmAccessWithRuntime({
    cfg,
    channel: CHANNEL_ID,
    accountId,
    dmPolicy: account.config.dmPolicy ?? "pairing",
    allowFrom: account.config.allowFrom,
    senderId: msg.senderHandle,
    rawBody,
    isSenderAllowed: isPulseBoardSenderAllowed,
    runtime: {
      shouldComputeCommandAuthorized: runtime.channel.commands.shouldComputeCommandAuthorized,
      resolveCommandAuthorizedFromAuthorizers:
        runtime.channel.commands.resolveCommandAuthorizedFromAuthorizers,
    },
  });

  if (access.access.decision !== "allow") {
    logInboundDrop({
      channel: CHANNEL_ID,
      accountId,
      reason: "dm-blocked",
      senderId: msg.senderHandle,
    });
    return;
  }

  await dispatchInboundDirectDmWithRuntime({
    cfg,
    runtime,
    channel: CHANNEL_ID,
    channelLabel: "PulseBoard",
    accountId,
    peer: { kind: "direct", id: msg.senderHandle },
    senderId: msg.senderHandle,
    senderAddress: `pulseboard:${msg.senderHandle}`,
    recipientAddress: `pulseboard:${account.botHandle}`,
    conversationLabel: msg.senderHandle,
    rawBody,
    messageId: msg.messageId,
    timestamp: msg.timestamp,
    commandAuthorized: access.commandAuthorized,
    deliver: async (payload) => {
      const outText =
        payload && typeof payload === "object" && "text" in payload
          ? String((payload as { text?: string }).text ?? "")
          : "";
      if (outText.trim()) {
        await sendMessagePulseBoard(msg.senderHandle, outText, { accountId });
      }
    },
    onRecordError: (err) => {
      runtime.logging
        .getChildLogger()
        .error?.(`[${accountId}] failed recording PulseBoard DM session: ${String(err)}`);
    },
    onDispatchError: (err, info) => {
      runtime.logging
        .getChildLogger()
        .error?.(`[${accountId}] PulseBoard DM ${info.kind} reply failed: ${String(err)}`);
    },
  });

  // Record inbound activity for status tracking.
  try {
    runtime.channel.activity.record({ channel: CHANNEL_ID, accountId, direction: "inbound" });
  } catch {
    // Best-effort.
  }
}

/**
 * Handle an incoming board (group) message from the PulseBoard API.
 * Uses per-board group policy to decide whether to respond.
 */
async function handleBoardMessage(
  msg: PulseBoardInboundMessage,
  accountId: string,
  cfg: CoreConfig,
): Promise<void> {
  const runtime = getPulseBoardRuntime();
  const rawBody = msg.text.trim();
  const boardName = msg.boardName ?? msg.target;
  const account = resolvePulseBoardAccount({ cfg, accountId });

  // Determine effective group policy for this board.
  const boardConfig = account.config.groups?.[boardName];
  const groupPolicy = resolveDefaultGroupPolicy(
    resolveAllowlistProviderRuntimeGroupPolicy({
      providerGroupPolicy: account.config.groupPolicy ?? "allowlist",
      hasGroups: Boolean(account.config.groups && Object.keys(account.config.groups).length > 0),
      hasGroupAllowFrom: Boolean(
        account.config.groupAllowFrom && account.config.groupAllowFrom.length > 0,
      ),
    }),
  );

  // Check whether this board is in the allowlist when policy is "allowlist".
  if (groupPolicy === "allowlist") {
    const allowedBoards = new Set(
      Object.keys(account.config.groups ?? {}).map((b) => b.toLowerCase()),
    );
    if (!allowedBoards.has(boardName.toLowerCase())) {
      logInboundDrop({
        channel: CHANNEL_ID,
        accountId,
        reason: "group-not-allowlisted",
        senderId: msg.senderHandle,
      });
      return;
    }
  } else if (groupPolicy === "disabled") {
    return;
  }

  // Check sender allowlist for this board (if configured).
  const boardAllowFrom = boardConfig?.allowFrom ?? account.config.groupAllowFrom;
  if (boardAllowFrom && boardAllowFrom.length > 0) {
    const allowed = isPulseBoardSenderAllowed(
      msg.senderHandle,
      boardAllowFrom.map(String),
    );
    if (!allowed) {
      logInboundDrop({
        channel: CHANNEL_ID,
        accountId,
        reason: "group-sender-not-allowed",
        senderId: msg.senderHandle,
      });
      return;
    }
  }

  // Check mention requirement for this board.
  const requireMention = boardConfig?.requireMention ?? true;
  if (requireMention && !rawBody.toLowerCase().includes(`@${account.botHandle.toLowerCase()}`)) {
    // No mention and mention is required; silently drop.
    return;
  }

  // Dispatch as a "direct" peer routed by board name (board = the conversation target).
  await dispatchInboundDirectDmWithRuntime({
    cfg,
    runtime,
    channel: CHANNEL_ID,
    channelLabel: "PulseBoard",
    accountId,
    peer: { kind: "direct", id: boardName },
    senderId: msg.senderHandle,
    senderAddress: `pulseboard:${msg.senderHandle}`,
    recipientAddress: `pulseboard:${boardName}`,
    conversationLabel: `${boardName} / ${msg.senderHandle}`,
    rawBody,
    messageId: msg.messageId,
    timestamp: msg.timestamp,
    deliver: async (payload) => {
      const outText =
        payload && typeof payload === "object" && "text" in payload
          ? String((payload as { text?: string }).text ?? "")
          : "";
      if (outText.trim()) {
        await sendMessagePulseBoard(boardName, outText, { accountId });
      }
    },
    onRecordError: (err) => {
      runtime.logging
        .getChildLogger()
        .error?.(`[${accountId}] failed recording PulseBoard board session: ${String(err)}`);
    },
    onDispatchError: (err, info) => {
      runtime.logging
        .getChildLogger()
        .error?.(
          `[${accountId}] PulseBoard board ${info.kind} reply failed for ${boardName}: ${String(err)}`,
        );
    },
  });

  try {
    runtime.channel.activity.record({ channel: CHANNEL_ID, accountId, direction: "inbound" });
  } catch {
    // Best-effort.
  }
}

/**
 * Wrapper for the pre-crypto DM sender check so it can be called with
 * per-message account/config state without capturing stale values in a closure.
 */
async function authorizeDmSenderForAccount(
  senderHandle: string,
  accountId: string,
  cfg: CoreConfig,
): Promise<"allow" | "block" | "pairing"> {
  const runtime = getPulseBoardRuntime();
  const account = resolvePulseBoardAccount({ cfg, accountId });
  const access = await resolveInboundDirectDmAccessWithRuntime({
    cfg,
    channel: CHANNEL_ID,
    accountId,
    dmPolicy: account.config.dmPolicy ?? "pairing",
    allowFrom: account.config.allowFrom,
    senderId: senderHandle,
    rawBody: "",
    isSenderAllowed: isPulseBoardSenderAllowed,
    runtime: {
      shouldComputeCommandAuthorized: runtime.channel.commands.shouldComputeCommandAuthorized,
      resolveCommandAuthorizedFromAuthorizers:
        runtime.channel.commands.resolveCommandAuthorizedFromAuthorizers,
    },
  });
  if (access.access.decision === "allow") {
    return "allow";
  }
  if (access.access.decision === "pairing") {
    return "pairing";
  }
  return "block";
}

