import {
  createAllowFromSection,
  createPromptParsedAllowFromForAccount,
  createStandardChannelSetupStatus,
  setSetupChannelEnabled,
} from "openclaw/plugin-sdk/setup";
import type { ChannelSetupDmPolicy, ChannelSetupWizard } from "openclaw/plugin-sdk/setup";
import { formatDocsLink } from "openclaw/plugin-sdk/setup";
import { normalizeAccountId } from "openclaw/plugin-sdk/account-id";
import {
  listPulseBoardAccountIds,
  resolveDefaultPulseBoardAccountId,
  resolvePulseBoardAccount,
  DEFAULT_PULSEBOARD_API_URL,
} from "./accounts.js";
import { normalizePulseBoardAllowEntry } from "./normalize.js";
import { pulseBoardSetupAdapter, updatePulseBoardAccountConfig } from "./setup-core.js";
import type { CoreConfig } from "./types.js";

const channel = "pulseboard" as const;

const PULSEBOARD_SETUP_HELP_LINES = [
  "PulseBoard needs an API key and your bot's handle on the platform.",
  "API key format: pk_live_...",
  "Env vars supported: PULSEBOARD_API_KEY, PULSEBOARD_BOT_HANDLE, PULSEBOARD_API_URL.",
  `Default API URL: ${DEFAULT_PULSEBOARD_API_URL}`,
  `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
];

const PULSEBOARD_ALLOW_FROM_HELP_LINES = [
  "Allowlist PulseBoard DMs by sender handle.",
  "Examples:",
  "- alice",
  "- @alice",
  "Multiple entries: comma-separated.",
  `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
];

function parseListInput(raw: string): string[] {
  return raw
    .split(/[\n,;]+/g)
    .map((e) => e.trim())
    .filter(Boolean);
}

const promptPulseBoardAllowFrom = createPromptParsedAllowFromForAccount<CoreConfig>({
  defaultAccountId: (cfg) => resolveDefaultPulseBoardAccountId(cfg),
  noteTitle: "PulseBoard allowlist",
  noteLines: PULSEBOARD_ALLOW_FROM_HELP_LINES,
  message: "PulseBoard allowFrom (handle or @handle)",
  placeholder: "alice, @bob",
  parseEntries: (raw) => ({
    entries: parseListInput(raw)
      .map((e) => normalizePulseBoardAllowEntry(e))
      .filter((e): e is string => Boolean(e)),
  }),
  getExistingAllowFrom: ({ cfg }) =>
    (cfg.channels?.pulseboard?.allowFrom ?? []).map(String),
  applyAllowFrom: ({ cfg, allowFrom }) =>
    updatePulseBoardAccountConfig(cfg as CoreConfig, "default", {
      allowFrom,
    }) as CoreConfig,
});

const pulseBoardDmPolicy: ChannelSetupDmPolicy = {
  label: "PulseBoard",
  channel,
  policyKey: "channels.pulseboard.dmPolicy",
  allowFromKey: "channels.pulseboard.allowFrom",
  getCurrent: (cfg) => (cfg as CoreConfig).channels?.pulseboard?.dmPolicy ?? "pairing",
  setPolicy: (cfg, policy) =>
    updatePulseBoardAccountConfig(cfg as CoreConfig, "default", { dmPolicy: policy }) as CoreConfig,
  promptAllowFrom: async ({ cfg, prompter, accountId }) =>
    promptPulseBoardAllowFrom({ cfg: cfg as CoreConfig, prompter, accountId }),
};

export const pulseBoardSetupWizard: ChannelSetupWizard = {
  channel,
  status: createStandardChannelSetupStatus({
    channelLabel: "PulseBoard",
    configuredLabel: "configured",
    unconfiguredLabel: "needs API key + bot handle",
    configuredHint: "configured",
    unconfiguredHint: "needs API key + bot handle",
    configuredScore: 1,
    unconfiguredScore: 0,
    includeStatusLine: true,
    resolveConfigured: ({ cfg }) =>
      listPulseBoardAccountIds(cfg as CoreConfig).some(
        (accountId) =>
          resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).configured,
      ),
  }),
  introNote: {
    title: "PulseBoard setup",
    lines: PULSEBOARD_SETUP_HELP_LINES,
    shouldShow: ({ cfg, accountId }) =>
      !resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).configured,
  },
  prepare: async ({ cfg, accountId, credentialValues, prompter }) => {
    const isDefault = normalizeAccountId(accountId) === "default";
    const resolved = resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId });
    const envKey = isDefault ? process.env.PULSEBOARD_API_KEY?.trim() : "";
    const envHandle = isDefault ? process.env.PULSEBOARD_BOT_HANDLE?.trim() : "";
    const envReady = Boolean(envKey && envHandle && !resolved.configured);

    if (envReady) {
      const useEnv = await prompter.confirm({
        message: "PULSEBOARD_API_KEY and PULSEBOARD_BOT_HANDLE detected. Use env vars?",
        initialValue: true,
      });
      if (useEnv) {
        return {
          cfg: updatePulseBoardAccountConfig(cfg as CoreConfig, accountId, { enabled: true }),
          credentialValues: { ...credentialValues, __pbUseEnv: "1" },
        };
      }
    }

    return {
      cfg: updatePulseBoardAccountConfig(cfg as CoreConfig, accountId, { enabled: true }),
      credentialValues: { ...credentialValues, __pbUseEnv: "0" },
    };
  },
