          enabled: true,
          apiKey: resolvedValue,
        }),
      shouldPrompt: ({ credentialValues }) => credentialValues.__pbUseEnv !== "1",
    },
  ],
  textInputs: [
    {
      inputKey: "botHandle",
      message: "Bot handle on PulseBoard",
      currentValue: ({ cfg, accountId }) =>
        resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).config.botHandle ||
        undefined,
      shouldPrompt: ({ credentialValues }) => credentialValues.__pbUseEnv !== "1",
      validate: ({ value }) => (String(value ?? "").trim() ? undefined : "Required"),
      normalizeValue: ({ value }) => String(value).trim().replace(/^@/, ""),
      applySet: async ({ cfg, accountId, value }) =>
        updatePulseBoardAccountConfig(cfg as CoreConfig, accountId, {
          enabled: true,
          botHandle: value,
        }),
    },
    {
      inputKey: "apiUrl",
      message: "PulseBoard API URL (optional)",
      placeholder: DEFAULT_PULSEBOARD_API_URL,
      required: false,
      applyEmptyValue: true,
      currentValue: ({ cfg, accountId }) => {
        const account = resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId });
