        return url && url !== DEFAULT_PULSEBOARD_API_URL ? url : undefined;
      },
      validate: ({ value }) => {
        const v = String(value ?? "").trim();
        if (!v) {
          return undefined;
        }
        try {
          new URL(v);
          return undefined;
        } catch {
          return "Must be a valid URL";
        }
      },
      normalizeValue: ({ value }) => String(value).trim(),
      applySet: async ({ cfg, accountId, value }) =>
        updatePulseBoardAccountConfig(cfg as CoreConfig, accountId, {
          enabled: true,
          apiUrl: value || undefined,
        }),
