import { describe, expect, it } from "vitest";
import { resolvePulseBoardAccount } from "./accounts.js";
import {
  isBoardTarget,
  normalizePulseBoardAllowEntry,
  normalizePulseBoardTarget,
} from "./normalize.js";
import type { CoreConfig } from "./types.js";

// ─── normalize.ts ──────────────────────────────────────────────────────────────

describe("normalizePulseBoardTarget", () => {
  it("normalizes board targets to lowercase with leading #", () => {
    expect(normalizePulseBoardTarget("#General")).toBe("#general");
    expect(normalizePulseBoardTarget("#Ops-2026")).toBe("#ops-2026");
    expect(normalizePulseBoardTarget("#hello_world")).toBe("#hello_world");
  });

  it("normalizes DM handles by stripping @ and lowercasing", () => {
    expect(normalizePulseBoardTarget("Alice")).toBe("alice");
    expect(normalizePulseBoardTarget("@Bob")).toBe("bob");
    expect(normalizePulseBoardTarget("carol.doe")).toBe("carol.doe");
  });

  it("returns null for empty or invalid targets", () => {
    expect(normalizePulseBoardTarget("")).toBeNull();
    expect(normalizePulseBoardTarget("  ")).toBeNull();
    expect(normalizePulseBoardTarget("#")).toBeNull();
  });
});

describe("isBoardTarget", () => {
  it("returns true for board names starting with #", () => {
    expect(isBoardTarget("#general")).toBe(true);
    expect(isBoardTarget("#ops")).toBe(true);
  });

  it("returns false for DM handles", () => {
    expect(isBoardTarget("alice")).toBe(false);
    expect(isBoardTarget("@bob")).toBe(false);
  });
});

describe("normalizePulseBoardAllowEntry", () => {
  it('passes through wildcard "*" unchanged', () => {
    expect(normalizePulseBoardAllowEntry("*")).toBe("*");
  });

  it("strips @ prefix and lowercases handles", () => {
    expect(normalizePulseBoardAllowEntry("@Alice")).toBe("alice");
    expect(normalizePulseBoardAllowEntry("Bob")).toBe("bob");
  });

  it("returns null for empty or whitespace-only entries", () => {
    expect(normalizePulseBoardAllowEntry("")).toBeNull();
    expect(normalizePulseBoardAllowEntry("   ")).toBeNull();
  });
});

// ─── accounts.ts ───────────────────────────────────────────────────────────────

describe("resolvePulseBoardAccount", () => {
  const makeCfg = (override?: object): CoreConfig => ({
    channels: {
      pulseboard: {
        apiKey: "pk_live_test123",
        botHandle: "testbot",
        enabled: true,
        ...override,
      },
    },
  });

  it("resolves configured status when apiKey and botHandle are present", () => {
    const account = resolvePulseBoardAccount({ cfg: makeCfg() });
    expect(account.configured).toBe(true);
    expect(account.apiKey).toBe("pk_live_test123");
    expect(account.botHandle).toBe("testbot");
  });

  it("marks account unconfigured when apiKey is missing", () => {
    const account = resolvePulseBoardAccount({ cfg: makeCfg({ apiKey: undefined }) });
    expect(account.configured).toBe(false);
  });

  it("marks account unconfigured when botHandle is missing", () => {
    const account = resolvePulseBoardAccount({ cfg: makeCfg({ botHandle: undefined }) });
    expect(account.configured).toBe(false);
  });

  it("uses default API URL when apiUrl is not configured", () => {
    const account = resolvePulseBoardAccount({ cfg: makeCfg() });
    expect(account.apiUrl).toBe("https://api.pulseboard.io");
  });

  it("respects a custom apiUrl", () => {
    const account = resolvePulseBoardAccount({
      cfg: makeCfg({ apiUrl: "https://selfhosted.example.com" }),
    });
    expect(account.apiUrl).toBe("https://selfhosted.example.com");
  });

  it("marks account disabled when enabled=false", () => {
    const account = resolvePulseBoardAccount({ cfg: makeCfg({ enabled: false }) });
    expect(account.enabled).toBe(false);
  });

  it("uses the default account ID when none is specified", () => {
    const account = resolvePulseBoardAccount({ cfg: makeCfg() });
    expect(account.accountId).toBe("default");
  });

  it("returns an unconfigured account for an empty config", () => {
    const account = resolvePulseBoardAccount({ cfg: {} });
    expect(account.configured).toBe(false);
    expect(account.enabled).toBe(true);
  });
});

