import type { ChannelSetupAdapter, ChannelSetupInput } from "openclaw/plugin-sdk/channel-setup";
import {
  applyAccountNameToChannelSection,
  createSetupInputPresenceValidator,
} from "openclaw/plugin-sdk/setup";
import { normalizeAccountId } from "openclaw/plugin-sdk/account-id";
import { patchScopedAccountConfig } from "openclaw/plugin-sdk/setup";
import type { CoreConfig, PulseBoardAccountConfig } from "./types.js";

const channel = "pulseboard" as const;

type PulseBoardSetupInput = ChannelSetupInput & {
  apiKey?: string;
  botHandle?: string;
  apiUrl?: string;
};

/**
 * Apply a partial config patch to the given account within channels.pulseboard.
 */
export function updatePulseBoardAccountConfig(
  cfg: CoreConfig,
  accountId: string,
  patch: Partial<PulseBoardAccountConfig>,
): CoreConfig {
  return patchScopedAccountConfig({
    cfg,
    channelKey: channel,
    accountId,
    patch,
    ensureChannelEnabled: false,
    ensureAccountEnabled: false,
  }) as CoreConfig;
}

/**
 * CLI/programmatic setup adapter for PulseBoard.
 * Validates and applies apiKey, botHandle, and optional apiUrl.
 */
export const pulseBoardSetupAdapter: ChannelSetupAdapter = {
  resolveAccountId: ({ accountId }) => normalizeAccountId(accountId),
  applyAccountName: ({ cfg, accountId, name }) =>
    applyAccountNameToChannelSection({
      cfg,
      channelKey: channel,
      accountId,
      name,
    }),
  validateInput: createSetupInputPresenceValidator({
    whenNotUseEnv: [
      { someOf: ["apiKey"], message: "PulseBoard requires --api-key." },
      { someOf: ["botHandle"], message: "PulseBoard requires --bot-handle." },
    ],
  }),
  applyAccountConfig: ({ cfg, accountId, input }) => {
    const setup = input as PulseBoardSetupInput;
    const patch: Partial<PulseBoardAccountConfig> = {
      enabled: true,
      apiKey: setup.apiKey?.trim(),
      botHandle: setup.botHandle?.trim(),
    };
    if (setup.apiUrl?.trim()) {
      patch.apiUrl = setup.apiUrl.trim();
    }
    return updatePulseBoardAccountConfig(cfg as CoreConfig, accountId, patch) as CoreConfig;
  },
};

